{
  "name": "Medicaid",
  "eligibility": {
    "age": 65,
    "income_limits": "For seniors (age 65+): Individual: $1,732/month (2024); Married couple both applying: $2,351/month combined (2024). Limits based on Federal Poverty Level (FPL) vary by group; e.g., for age 65+ or disabled, household of 1: $22,025 yearly (effective Jan 2026). Spousal rules allow Community Spouse Monthly Income Allowance up to $3,853.50 (2024) if spouse's income is below that.[2][7]",
    "asset_limits": "Individual: $30,182 countable resources (2024). Exempt: primary residence (up to $1,071,000 equity), one car, personal property. Countable assets exceed limits require spend-down. 60-month look-back period reviews transfers below fair market value, imposing penalty ineligibility period.[1][2]",
    "other_requirements": ["Legal U.S. resident of NY state/county with intent to remain.", "Medical need (e.g., ADL criteria via NY Independent Assessor for home care).", "For ages 21-65: must be disabled, blind, or meet SSI levels.", "Categorically needy or meet financial thresholds."][1][2][3][4]
  },
  "benefits": {
    "type": "service",
    "value": "Long-term care: nursing home, home care (personal care services/PCS, consumer directed personal assistance/CDPAP), community care. Covers costs not paid by Medicare (which excludes long-term care). Assessed via NY Independent Assessor (NIAP) for ADL eligibility determining service hours.[1][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: NY State of Health (for MAGI groups) or Local Department of Social Services (LDSS) for non-MAGI (seniors 65+, disabled).", "Local Department of Social Services (LDSS) offices for seniors.", "Phone/mail/in-person via LDSS.", "Specific phone/website not in results; contact local LDSS."][6],
    "processing_time": "Not specified in results.",
    "waitlist": "Possible penalty period from look-back violations; no general waitlist noted.[1]",
    "forms": ["Not specified; varies by LDSS."],
    "documents": ["Proof of income, assets, residency, citizenship/immigration status, medical need documentation."][1][2]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered by county LDSS; apply in county of residence.[1][6]",
    "regional_variations": "Processing and providers may vary by county LDSS; no specific wait time differences noted.[6]",
    "offices_or_providers": ["Local Department of Social Services (LDSS) by county."]
  },
  "official_source": "https://www.ny.gov/services/apply-medicaid",
  "gotchas": ["60-month look-back delays eligibility for improper transfers.", "Medicare does not cover long-term care; Medicaid does.", "Spousal impoverishment rules protect community spouse but require planning.", "Must pass ADL/medical need via NIAP for home care.", "Non-MAGI seniors apply via LDSS, not NY State of Health.", "Assets over limit need spend-down."[1][2][4][6]],
  "data_shape_notes": "County-administered with statewide rules; income/assets for seniors; look-back and spousal protections unique; ADL assessment via NIAP for services; data from 2024/2026, verify current limits."
}

