{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; program is free and open to all qualifying residents regardless of financial status.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Must reside (or be considering placement) in a long-term care facility such as nursing homes, assisted living, adult care homes, family-type homes, or board and care facilities in New York.", "Open to residents, family members, friends, facility staff, or anyone concerned about a resident's welfare.", "People with disabilities are included, not limited to seniors."][1][2][3][4][5]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy to protect rights and resolve complaints; investigation and mediation of issues like care quality, abuse/neglect, residents' rights, financial concerns, food service, medical services, and staff misunderstandings; education for residents, families, and staff; referrals to Department of Health or other agencies if needed; promotion of resident/family councils. Provided by trained volunteer ombudsmen (2-4 hours/week per facility on average) and paid staff. Confidential unless permission given to share details. Free service."[1][2][3][5],
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Statewide toll-free 1-855-582-6769 (primary contact for local ombudsman).", "Regional examples: Western NY 844-527-5509 or 716-817-9222; CIDNY/NYC area 888-855-9807; Broome etc. 607-722-1251.", "Email for info/volunteering: ltcop@cidny.org (CIDNY).", "Contact local Regional Ombudsman Coordinator via state office.", "In-person: Visit assigned facility's ombudsman or regional sponsor offices (e.g., People Inc. in Buffalo)."][1][2][4][5],
    "processing_time": "Immediate assistance upon contact; no formal processing as it's complaint/response-based advocacy, not an enrollment program.",
    "waitlist": null,
    "forms": ["No specific application forms required; contact by phone or email to report concerns or seek assistance."],
    "documents": ["No documents needed to initiate contact; provide details of the complaint or concern verbally or in writing. Confidentiality protected."][1][2][3]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available throughout New York State for residents of licensed long-term care facilities.",
    "regional_variations": "Administered regionally by non-profit organizations, independent living centers, and area agencies on aging under State Ombudsman supervision. Different regional coordinators, sponsors, and contact numbers (e.g., People Inc. for Erie/Niagara/Chautauqua/Cattaraugus; Action for Older Persons for Broome/Chenango/Delaware/Tioga; CIDNY for other areas). No noted differences in services, but local offices handle specific counties.",
    "offices_or_providers": ["Statewide coordination via Office for the Aging.", "Examples: People Inc. (Buffalo, 2747 Main St, 2nd Floor), CIDNY, Action for Older Persons."][1][2][4][5][6]
  },
  "official_source": "https://aging.ny.gov/long-term-care-ombudsman-program",
  "gotchas": ["Not a direct service provider (e.g., no healthcare, housing, or financial aid)—only advocacy and complaint resolution.", "Requires resident permission to act on complaints due to strict confidentiality.", "Primarily relies on volunteers, so availability tied to facility assignments.", "Open to non-residents (families, prospective residents), but focused on current facility residents.", "Funded under Older Americans Act; not means-tested, unlike Medicaid or income-based programs."][1][2][3],
  "data_shape_notes": "no income test; advocacy-only (not financial/services); statewide but regionally administered by local non-profits with varying contacts; volunteer-driven; confidential complaint-based access"
}
